import {
  forwardRef,
  type ElementType,
  type HTMLAttributes,
  type ReactNode,
} from 'react';
import { cn, vc } from '../../utils/cn';
import styles from './Card.module.css';

export type CardVariant = 'elevated' | 'outlined' | 'flat';
export type CardPadding = 'none' | 'sm' | 'md' | 'lg';

export interface CardOwnProps {
  variant?: CardVariant;
  padding?: CardPadding;
  as?: ElementType;
  children?: ReactNode;
  className?: string;
}

type CardProps = CardOwnProps &
  Omit<HTMLAttributes<HTMLElement>, keyof CardOwnProps>;

const CardRoot = forwardRef<HTMLElement, CardProps>(function Card(
  {
    variant = 'elevated',
    padding = 'md',
    as,
    className,
    children,
    'data-testid': dataTestId = 'tatva-card',
    ...rest
  }: CardProps & { 'data-testid'?: string },
  ref,
) {
  const Component = (as ?? 'div') as ElementType;
  return (
    <Component
      ref={ref}
      className={cn(
        styles.card,
        vc(styles, 'variant', variant),
        vc(styles, 'padding', padding),
        className,
      )}
      data-testid={dataTestId}
      {...rest}
    >
      {children}
    </Component>
  );
});

export interface CardHeaderProps extends HTMLAttributes<HTMLDivElement> {
  divider?: boolean;
}
function CardHeader({
  className,
  divider,
  children,
  ...rest
}: CardHeaderProps) {
  return (
    <div
      className={cn(styles.header, divider && styles.headerDivider, className)}
      {...rest}
    >
      {children}
    </div>
  );
}

function CardBody({
  className,
  children,
  ...rest
}: HTMLAttributes<HTMLDivElement>) {
  return (
    <div className={cn(styles.body, className)} {...rest}>
      {children}
    </div>
  );
}

export interface CardFooterProps extends HTMLAttributes<HTMLDivElement> {
  divider?: boolean;
}
function CardFooter({
  className,
  divider,
  children,
  ...rest
}: CardFooterProps) {
  return (
    <div
      className={cn(styles.footer, divider && styles.footerDivider, className)}
      {...rest}
    >
      {children}
    </div>
  );
}

/**
 * Compound Card component.
 * Usage: `<Card><Card.Header/><Card.Body/><Card.Footer/></Card>`
 */
export const Card = Object.assign(CardRoot, {
  Header: CardHeader,
  Body: CardBody,
  Footer: CardFooter,
});

export type { CardProps };

.card {
  background-color: var(--tatva-color-bg);
  color: var(--tatva-color-fg);
  border-radius: var(--tatva-radius-lg);
  overflow: hidden;
  transition: box-shadow var(--tatva-transition-fast);
}

.variantElevated {
  border: 1px solid transparent;
  box-shadow: var(--tatva-shadow-md);
}
.variantOutlined {
  border: 1px solid var(--tatva-color-border);
}
.variantFlat {
  border: 1px solid transparent;
  background-color: var(--tatva-color-bg-subtle);
}

.paddingNone {
}
.paddingSm {
  padding: var(--tatva-space-3);
}
.paddingMd {
  padding: var(--tatva-space-4);
}
.paddingLg {
  padding: var(--tatva-space-6);
}

.header {
  padding-bottom: var(--tatva-space-3);
}
.headerDivider {
  border-bottom: 1px solid var(--tatva-color-border);
  margin-bottom: var(--tatva-space-3);
}

.body {
  /* body content spans remaining space */
}

.footer {
  display: flex;
  justify-content: flex-end;
  gap: var(--tatva-space-2);
  padding-top: var(--tatva-space-3);
}
.footerDivider {
  border-top: 1px solid var(--tatva-color-border);
  margin-top: var(--tatva-space-3);
}

export { Card } from './Card';
export type {
  CardProps,
  CardOwnProps,
  CardHeaderProps,
  CardFooterProps,
  CardVariant,
  CardPadding,
} from './Card';
